{"content": "#ifndef FS_H
#define FS_H

#include <stddef.h>
#include <stdio.h>
#include <stdint.h>

#ifdef __cplusplus
extern "C" {
#endif

// A very simple proto filesystem stored in one binary file.
// Layout:
// [magic 4 bytes "PFS1"][uint32_t entry_count]
// Then repeated entries: [name_len(uint16_t)][name bytes][uint64_t offset][uint64_t size]
// After directory, raw file data blobs placed at given offsets.

#define PFS_MAGIC 0x50354631u /* 'P' 'F' '5' '1' */

typedef struct {
    char name[256];
    uint64_t offset;
    uint64_t size;
} pfs_entry;

// Handle for opened filesystem
typedef struct {
    FILE *fp;
    uint32_t count;
    pfs_entry *entries; // dynamic array of entries (max 1024 for simplicity)
    int dirty; // directory changed and needs flush
} pfs_t;

// Open or create filesystem at path. Returns NULL on error.
pfs_t *pfs_open(const char *path);

// Close filesystem, flushing directory if dirty.
void pfs_close(pfs_t *pfs);

// List files: prints to provided FILE* (stdout if null). Returns number listed or -1 on error.
int pfs_list(pfs_t *pfs, FILE *out);

// Write a file (create or overwrite). Data provided in memory buffer.
// Returns 0 on success.
int pfs_write(pfs_t *pfs, const char *name, const void *buf, size_t size);

// Read a file into buffer. If buf is NULL, just set *size_out to size.
// Caller allocates buffer of at least size bytes.
// Returns 0 on success.
int pfs_read(pfs_t *pfs, const char *name, void *buf, size_t *size_out);

// Rename a file. Returns 0 on success.
int pfs_rename(pfs_t *pfs, const char *old_name, const char *new_name);

// Remove a file. Returns 0 on success (data remains orphaned; compaction not implemented).
int pfs_remove(pfs_t *pfs, const char *name);

#ifdef __cplusplus
}
#endif

#endif // FS_H
